sql:
SELECT campaign_name
FROM test_campaigns
WHERE campaign_id = 1;

SELECT COUNT(anomaly_id) AS anomaly_count
FROM test_anomalies
WHERE anomaly_type = 'Temperature Spike';

SELECT AVG(JULIANDAY(ts.session_end) - JULIANDAY(ts.session_start)) AS average_aborted_session_duration
FROM test_sessions ts
WHERE ts.session_status = 'Aborted';

SELECT report_file, report_summary
FROM test_reports
ORDER BY report_date DESC;

SELECT model_name, manufacturer
FROM engine_models
WHERE engine_type = 'Turbofan';

SELECT session_start, session_end
FROM test_sessions
WHERE session_id = 1;

SELECT COUNT(session_id) AS total_sessions
FROM test_sessions
WHERE model_id = (SELECT model_id FROM engine_models LIMIT 1);

SELECT anomaly_type, anomaly_severity
FROM test_anomalies
WHERE anomaly_type = 'Pressure Drop';

SELECT campaign_name, start_date, end_date
FROM test_campaigns
ORDER BY campaign_id;

SELECT campaign_name, engine_config, COUNT(*) AS total_campaigns
FROM test_campaigns
GROUP BY campaign_name, engine_config;

SELECT DISTINCT ts.session_id
FROM test_sessions ts
JOIN test_anomalies ta ON ts.session_id = ta.session_id;

SELECT COUNT(note_id) 
FROM test_notes 
WHERE session_id = 0;

SELECT campaign_name, start_date
FROM test_campaigns
ORDER BY start_date ASC;
